class Solution:
    def kthLargestLevelSum(self, root, k):
        depth_sum = {}
        def dfs(node, d):
            if not node:
                return
            depth_sum[d] = depth_sum.get(d, 0) + node.val
            dfs(node.left, d + 1)
            dfs(node.right, d + 1)
        dfs(root, 0)
        sums = sorted(depth_sum.values(), reverse=True)
        if k > len(sums):
            return -1
        return sums[k - 1]

