class Solution:
    def kthLargestLevelSum(self, root, k):
        from collections import deque
        sums = []
        dq = deque([root])
        while dq:
            total = 0
            for _ in range(len(dq)):
                node = dq.popleft()
                total += node.val
                if node.left:
                    dq.append(node.left)
                if node.right:
                    dq.append(node.right)
            sums.append(total)
        if k > len(sums):
            return -1
        sums.sort(reverse=True)
        return sums[k - 1]

