var kthLargestLevelSum = function(root, k) {
    const sums = [];
    let level = [root];
    while (level.length) {
        let total = 0;
        const next = [];
        for (const node of level) {
            total += node.val;
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        sums.push(total);
        level = next;
    }
    if (k > sums.length) return -1;
    sums.sort((a, b) => b - a);
    return sums[k - 1];
};
